-- Whole Wheat Veggie-Loaded Pizza
INSERT INTO public.recipes
  (id, title, subtitle, emoji, image_url, tags, meal, categories, diet, is_kids, prep_minutes, cook_minutes, servings, nutrition, ingredients, dressing, base_ingredients, steps, i18n)
VALUES (
  'margherita-pizza', 'Whole Wheat Veggie-Loaded Pizza', 'Homemade whole-wheat crust piled with garden vegetables and melty mozzarella', '🍕', NULL,
  ARRAY['Vegetarian','Kid-Friendly'], ARRAY['Main Course'], ARRAY['Pizza'], ARRAY['vegetarian'],
  true, 30, 15, 8,
  '{"kcal":310,"protein":14,"carbs":38,"fat":11,"fiber":6}'::jsonb,
  '[{"name":"Whole wheat flour (or half wholemeal, half spelt)","emoji":"🌾","amount":"375 g"},{"name":"Instant dry yeast","emoji":"🫙","amount":"7 g (1 sachet)"},{"name":"Extra-virgin olive oil (for dough)","emoji":"🫒","amount":"2 tbsp"},{"name":"Fine sea salt (for dough)","emoji":"🧂","amount":"1 tsp"},{"name":"Honey","emoji":"🍯","amount":"1 tsp"},{"name":"Warm water","emoji":"💧","amount":"240 ml"},{"name":"Tomato passata","emoji":"🥫","amount":"250 ml"},{"name":"Low-moisture mozzarella, grated","emoji":"🧀","amount":"200 g"},{"name":"Parmesan, finely grated","emoji":"🧀","amount":"30 g"},{"name":"Red bell pepper, thinly sliced","emoji":"🫑","amount":"1 medium"},{"name":"Courgette, thinly sliced","emoji":"🥒","amount":"1 small"},{"name":"Red onion, thinly sliced","emoji":"🧅","amount":"½ medium"},{"name":"Cherry tomatoes, halved","emoji":"🍅","amount":"150 g"},{"name":"Chestnut mushrooms, sliced","emoji":"🍄","amount":"100 g"},{"name":"Baby spinach","emoji":"🥬","amount":"60 g"},{"name":"Fresh basil or rocket, to finish","emoji":"🌿","amount":"1 handful"}]'::jsonb,
  NULL,
  '["Olive oil","Semolina or cornmeal, for dusting"]'::jsonb,
  '[{"title":"Make the dough","text":"Stir the yeast and honey into the warm water and let sit 5 minutes until foamy. Add the flour, salt and olive oil, then knead 5–7 minutes to a smooth, slightly tacky ball.","ings":[]},{"title":"Prove","text":"Place in an oiled bowl, cover, and leave in a warm spot about 1 hour until nearly doubled.","ings":[]},{"title":"Prep veg & preheat","text":"Put a pizza stone or tray in the oven and preheat to its hottest setting (250°C). Thinly slice all the vegetables.","ings":[]},{"title":"Shape the base","text":"Divide the dough in two and stretch each into a rustic 28 cm round on semolina-dusted parchment, edges a little thicker.","ings":[]},{"title":"Top the pizzas","text":"Spread a thin layer of passata, scatter over mozzarella and parmesan, then arrange the vegetables and spinach. Drizzle with olive oil and a pinch of salt.","ings":[]},{"title":"Bake hot","text":"Bake 12–15 minutes until the crust is golden and crisp and the cheese is bubbling and browned.","ings":[]},{"title":"Finish","text":"Scatter with fresh basil or rocket, slice and serve straight away.","ings":[]}]'::jsonb,
  '{"de":{"title":"Vollkornpizza, üppig mit Gemüse belegt","subtitle":"Selbstgemachter Vollkornboden, reichlich belegt mit Gartengemüse und zerlaufendem Mozzarella","ingredients":["Vollkornmehl (oder halb Vollkorn, halb Dinkel)","Trockenhefe","Natives Olivenöl extra (für den Teig)","Feines Meersalz (für den Teig)","Honig","Warmes Wasser","Passierte Tomaten","Fester Mozzarella, gerieben","Parmesan, fein gerieben","Rote Paprika, in dünne Scheiben","Zucchini, in dünne Scheiben","Rote Zwiebel, in dünne Ringe","Kirschtomaten, halbiert","Braune Champignons, in Scheiben","Babyspinat","Frisches Basilikum oder Rucola zum Schluss"],"base":["Olivenöl","Hartweizengrieß oder Maismehl zum Bestäuben"],"steps":[{"title":"Teig ansetzen","text":"Rühr Hefe und Honig ins warme Wasser und lass alles 5 Minuten stehen, bis es schäumt. Gib Mehl, Salz und Olivenöl dazu und knete 5–7 Minuten zu einer glatten, leicht klebrigen Kugel."},{"title":"Gehen lassen","text":"Leg den Teig in eine geölte Schüssel, deck ihn ab und lass ihn an einem warmen Ort etwa 1 Stunde gehen, bis er fast doppelt so groß ist."},{"title":"Gemüse & Ofen vorbereiten","text":"Schieb einen Pizzastein oder ein Blech in den Ofen und heiz ihn auf höchster Stufe vor (250°C). Schneide das gesamte Gemüse in dünne Scheiben."},{"title":"Boden formen","text":"Teile den Teig in zwei Hälften und zieh jede auf mit Grieß bestäubtem Backpapier zu einem rustikalen Kreis von 28 cm aus, den Rand etwas dicker."},{"title":"Pizzen belegen","text":"Streich eine dünne Schicht passierte Tomaten auf, verteil Mozzarella und Parmesan darüber und leg dann das Gemüse und den Spinat auf. Beträufle alles mit Olivenöl und einer Prise Salz."},{"title":"Heiß backen","text":"Backe die Pizza 12–15 Minuten, bis der Rand goldbraun und knusprig ist und der Käse blubbert und Farbe bekommt."},{"title":"Zum Schluss","text":"Streu frisches Basilikum oder Rucola darüber, schneide die Pizza in Stücke und serviere sie sofort."}]},"fr":{"title":"Pizza complète généreusement garnie de légumes","subtitle":"Pâte complète maison garnie à foison de légumes du jardin et de mozzarella fondante","ingredients":["Farine complète (ou moitié complète, moitié épeautre)","Levure sèche instantanée","Huile d''olive vierge extra (pour la pâte)","Sel fin de mer (pour la pâte)","Miel","Eau tiède","Purée de tomates","Mozzarella à pizza, râpée","Parmesan, finement râpé","Poivron rouge, émincé","Courgette, émincée","Oignon rouge, émincé","Tomates cerises, coupées en deux","Champignons bruns, émincés","Jeunes pousses d''épinard","Basilic frais ou roquette, pour la finition"],"base":["Huile d''olive","Semoule ou farine de maïs, pour saupoudrer"],"steps":[{"title":"Préparer la pâte","text":"Délaie la levure et le miel dans l''eau tiède et laisse reposer 5 minutes, jusqu''à ce que ça mousse. Ajoute la farine, le sel et l''huile d''olive, puis pétris 5 à 7 minutes pour obtenir une boule lisse et légèrement collante."},{"title":"Laisser lever","text":"Dépose la pâte dans un saladier huilé, couvre et laisse lever environ 1 heure dans un endroit tiède, jusqu''à ce qu''elle ait presque doublé."},{"title":"Préparer les légumes & préchauffer","text":"Mets une pierre à pizza ou une plaque dans le four et préchauffe-le au maximum (250°C). Émince finement tous les légumes."},{"title":"Façonner la pâte","text":"Divise la pâte en deux et étale chaque morceau en un disque rustique de 28 cm sur du papier cuisson saupoudré de semoule, en laissant les bords un peu plus épais."},{"title":"Garnir les pizzas","text":"Étale une fine couche de purée de tomates, parsème de mozzarella et de parmesan, puis dispose les légumes et les épinards. Arrose d''un filet d''huile d''olive et d''une pincée de sel."},{"title":"Cuire bien chaud","text":"Enfourne 12 à 15 minutes, jusqu''à ce que la pâte soit dorée et croustillante et que le fromage bouillonne et soit bien coloré."},{"title":"Finir","text":"Parsème de basilic frais ou de roquette, coupe en parts et sers aussitôt."}]},"es":{"title":"Pizza integral cargada de verduras","subtitle":"Masa integral casera colmada de verduras de la huerta y mozzarella fundida","ingredients":["Harina integral (o mitad integral, mitad espelta)","Levadura seca instantánea","Aceite de oliva virgen extra (para la masa)","Sal marina fina (para la masa)","Miel","Agua templada","Tomate triturado","Mozzarella para pizza, rallada","Parmesano, rallado fino","Pimiento rojo, en láminas finas","Calabacín, en láminas finas","Cebolla roja, en aros finos","Tomates cherry, cortados por la mitad","Champiñones marrones, en láminas","Espinacas baby","Albahaca fresca o rúcula, para terminar"],"base":["Aceite de oliva","Sémola o harina de maíz, para espolvorear"],"steps":[{"title":"Preparar la masa","text":"Disuelve la levadura y la miel en el agua templada y deja reposar 5 minutos, hasta que haga espuma. Añade la harina, la sal y el aceite de oliva y amasa 5–7 minutos hasta lograr una bola lisa y ligeramente pegajosa."},{"title":"Dejar levar","text":"Coloca la masa en un bol aceitado, tápala y déjala en un lugar cálido alrededor de 1 hora, hasta que casi duplique su tamaño."},{"title":"Preparar la verdura y precalentar","text":"Mete una piedra para pizza o una bandeja en el horno y precaliéntalo al máximo (250°C). Corta toda la verdura en láminas finas."},{"title":"Formar la base","text":"Divide la masa en dos y estira cada parte en un círculo rústico de 28 cm sobre papel de horno espolvoreado con sémola, dejando los bordes un poco más gruesos."},{"title":"Cubrir las pizzas","text":"Extiende una capa fina de tomate triturado, reparte la mozzarella y el parmesano por encima y coloca la verdura y las espinacas. Riega con un chorrito de aceite de oliva y una pizca de sal."},{"title":"Hornear bien caliente","text":"Hornea 12–15 minutos, hasta que la base esté dorada y crujiente y el queso burbujee y se dore."},{"title":"Terminar","text":"Esparce albahaca fresca o rúcula, corta en porciones y sirve enseguida."}]}}'::jsonb
)
