-- Vegetarian Spinach & Ricotta Lasagna
INSERT INTO public.recipes
  (id, title, subtitle, emoji, image_url, tags, meal, categories, diet, is_kids, prep_minutes, cook_minutes, servings, nutrition, ingredients, dressing, base_ingredients, steps, i18n)
VALUES (
  'vegetarian-lasagna', 'Vegetarian Spinach & Ricotta Lasagna', 'No béchamel — layers of ricotta, mozzarella and parmesan over a rich veg-tomato sauce', '🍝', NULL,
  ARRAY['Vegetarian','Kid-Friendly'], ARRAY['Main Course'], ARRAY['Pasta'], ARRAY['vegetarian'],
  true, 30, 55, 6,
  '{"kcal":460,"protein":24,"carbs":40,"fat":22,"fiber":5}'::jsonb,
  '[{"name":"Dried lasagna sheets","emoji":"🍝","amount":"250 g (about 12)"},{"name":"Ricotta","emoji":"🧀","amount":"500 g"},{"name":"Mozzarella, grated","emoji":"🧀","amount":"250 g"},{"name":"Parmesan, finely grated","emoji":"🧀","amount":"60 g"},{"name":"Egg","emoji":"🥚","amount":"1 large"},{"name":"Tomato passata","emoji":"🥫","amount":"700 g"},{"name":"Crushed tomatoes","emoji":"🥫","amount":"400 g tin"},{"name":"Onion, finely chopped","emoji":"🧅","amount":"1 medium"},{"name":"Garlic, minced","emoji":"🧄","amount":"3 cloves"},{"name":"Olive oil","emoji":"🫒","amount":"3 tbsp"},{"name":"Baby spinach","emoji":"🥬","amount":"200 g"},{"name":"Courgette, diced","emoji":"🥒","amount":"1 medium"},{"name":"Chestnut mushrooms, sliced","emoji":"🍄","amount":"250 g"},{"name":"Fresh basil, chopped","emoji":"🌿","amount":"1 handful"},{"name":"Dried oregano","emoji":"🌿","amount":"1 tsp"}]'::jsonb,
  NULL,
  '["Salt","Black pepper","Olive oil"]'::jsonb,
  '[{"title":"Make the veg-tomato sauce","text":"Soften the onion in olive oil 5 minutes, add garlic, mushrooms and courgette and cook 8–10 minutes until their liquid evaporates. Stir in passata, crushed tomatoes and oregano, season, and simmer 15 minutes until thick.","ings":[]},{"title":"Wilt the spinach","text":"Stir the spinach through until just collapsed (or wilt separately, squeeze dry and chop for the ricotta mix).","ings":[]},{"title":"Mix the ricotta filling","text":"Combine ricotta, egg, most of the parmesan, the chopped spinach and half the basil, with salt and pepper, until smooth.","ings":[]},{"title":"Layer","text":"Spread a little sauce in the dish, add lasagna sheets, a third of the ricotta, sauce, then mozzarella. Repeat the layers twice more.","ings":[]},{"title":"Finish the top","text":"End with sheets, the last of the sauce, remaining mozzarella and reserved parmesan for a golden crust.","ings":[]},{"title":"Bake","text":"Bake at 190°C covered with foil 30 minutes, then uncovered 20–25 minutes until golden and bubbling.","ings":[]},{"title":"Rest & serve","text":"Rest 15–20 minutes so the layers set, scatter with basil, slice and serve.","ings":[]}]'::jsonb,
  '{"de":{"title":"Vegetarische Spinat-Ricotta-Lasagne","subtitle":"Ohne Béchamel – Schichten aus Ricotta, Mozzarella und Parmesan auf einer kräftigen Gemüse-Tomaten-Sauce","ingredients":["Getrocknete Lasagneplatten","Ricotta","Mozzarella, gerieben","Parmesan, fein gerieben","Ei","Passierte Tomaten","Stückige Tomaten","Zwiebel, fein gehackt","Knoblauch, fein gehackt","Olivenöl","Babyspinat","Zucchini, gewürfelt","Braune Champignons, in Scheiben","Frisches Basilikum, gehackt","Getrockneter Oregano"],"base":["Salz","Schwarzer Pfeffer","Olivenöl"],"steps":[{"title":"Gemüse-Tomaten-Sauce kochen","text":"Dünste die Zwiebel 5 Minuten in Olivenöl an, gib Knoblauch, Champignons und Zucchini dazu und brate alles 8–10 Minuten, bis die Flüssigkeit verdampft ist. Rühr passierte Tomaten, stückige Tomaten und Oregano unter, würze und lass die Sauce 15 Minuten einköcheln, bis sie dickflüssig ist."},{"title":"Spinat zusammenfallen lassen","text":"Rühr den Spinat unter, bis er gerade zusammengefallen ist (oder lass ihn separat zusammenfallen, drück ihn aus und hack ihn für die Ricotta-Masse)."},{"title":"Ricotta-Füllung anrühren","text":"Verrühre Ricotta, Ei, den größten Teil des Parmesans, den gehackten Spinat und die Hälfte des Basilikums mit Salz und Pfeffer zu einer glatten Masse."},{"title":"Schichten","text":"Streich etwas Sauce in die Form, leg Lasagneplatten darauf, dann ein Drittel der Ricotta-Masse, Sauce und Mozzarella. Wiederhole die Schichten noch zweimal."},{"title":"Oberste Schicht","text":"Schließe mit Lasagneplatten, der restlichen Sauce, dem übrigen Mozzarella und dem zurückbehaltenen Parmesan ab – für eine goldbraune Kruste."},{"title":"Backen","text":"Backe die Lasagne bei 190°C zunächst 30 Minuten mit Alufolie abgedeckt, dann ohne Folie weitere 20–25 Minuten, bis sie goldbraun ist und blubbert."},{"title":"Ruhen lassen & servieren","text":"Lass die Lasagne 15–20 Minuten ruhen, damit sich die Schichten setzen, streu Basilikum darüber, schneide sie an und serviere."}]},"fr":{"title":"Lasagnes végétariennes épinards-ricotta","subtitle":"Sans béchamel — des couches de ricotta, mozzarella et parmesan sur une sauce tomate-légumes bien relevée","ingredients":["Feuilles de lasagnes sèches","Ricotta","Mozzarella, râpée","Parmesan, finement râpé","Œuf","Purée de tomates","Tomates concassées","Oignon, finement haché","Ail, haché","Huile d''olive","Jeunes pousses d''épinard","Courgette, en dés","Champignons bruns, émincés","Basilic frais, ciselé","Origan séché"],"base":["Sel","Poivre noir","Huile d''olive"],"steps":[{"title":"Préparer la sauce tomate-légumes","text":"Fais suer l''oignon 5 minutes dans l''huile d''olive, ajoute l''ail, les champignons et la courgette et fais cuire 8 à 10 minutes, jusqu''à ce que l''eau de végétation s''évapore. Incorpore la purée de tomates, les tomates concassées et l''origan, assaisonne et laisse mijoter 15 minutes, jusqu''à épaississement."},{"title":"Faire tomber les épinards","text":"Mélange les épinards jusqu''à ce qu''ils soient tout juste tombés (ou fais-les tomber à part, presse-les pour les égoutter et hache-les pour l''appareil à la ricotta)."},{"title":"Préparer la garniture à la ricotta","text":"Mélange la ricotta, l''œuf, la majeure partie du parmesan, les épinards hachés et la moitié du basilic, avec du sel et du poivre, jusqu''à obtenir une texture lisse."},{"title":"Monter les lasagnes","text":"Étale un peu de sauce au fond du plat, ajoute des feuilles de lasagnes, un tiers de la ricotta, de la sauce, puis de la mozzarella. Répète ces couches encore deux fois."},{"title":"Finir le dessus","text":"Termine par des feuilles de lasagnes, le reste de la sauce, la mozzarella restante et le parmesan réservé pour une croûte dorée."},{"title":"Enfourner","text":"Fais cuire à 190°C, couvert de papier alu, pendant 30 minutes, puis à découvert 20 à 25 minutes, jusqu''à ce que ce soit doré et bouillonnant."},{"title":"Laisser reposer & servir","text":"Laisse reposer 15 à 20 minutes pour que les couches se tiennent, parsème de basilic, coupe des parts et sers."}]},"es":{"title":"Lasaña vegetariana de espinacas y ricotta","subtitle":"Sin bechamel — capas de ricotta, mozzarella y parmesano sobre una sabrosa salsa de tomate y verduras","ingredients":["Placas de lasaña secas","Ricotta","Mozzarella, rallada","Parmesano, rallado fino","Huevo","Tomate triturado","Tomate troceado","Cebolla, picada fina","Ajo, picado","Aceite de oliva","Espinacas baby","Calabacín, en dados","Champiñones marrones, en láminas","Albahaca fresca, picada","Orégano seco"],"base":["Sal","Pimienta negra","Aceite de oliva"],"steps":[{"title":"Preparar la salsa de tomate y verduras","text":"Pocha la cebolla 5 minutos en aceite de oliva, añade el ajo, los champiñones y el calabacín y cocina 8–10 minutos, hasta que se evapore su líquido. Incorpora el tomate triturado, el tomate troceado y el orégano, salpimenta y deja cocer a fuego lento 15 minutos, hasta que espese."},{"title":"Rehogar las espinacas","text":"Mezcla las espinacas hasta que apenas se ablanden (o rehógalas aparte, escúrrelas bien y pícalas para la mezcla de ricotta)."},{"title":"Preparar el relleno de ricotta","text":"Mezcla la ricotta, el huevo, casi todo el parmesano, las espinacas picadas y la mitad de la albahaca con sal y pimienta, hasta que quede una crema homogénea."},{"title":"Montar la lasaña","text":"Extiende un poco de salsa en la fuente, coloca placas de lasaña, un tercio de la ricotta, salsa y luego mozzarella. Repite las capas dos veces más."},{"title":"Rematar la superficie","text":"Termina con placas, el resto de la salsa, la mozzarella que quede y el parmesano reservado para lograr una costra dorada."},{"title":"Hornear","text":"Hornea a 190°C tapada con papel de aluminio 30 minutos y luego destapada 20–25 minutos, hasta que esté dorada y burbujeante."},{"title":"Reposar y servir","text":"Deja reposar 15–20 minutos para que las capas se asienten, esparce albahaca, corta y sirve."}]}}'::jsonb
)
ON CONFLICT (id) DO UPDATE SET
  title=EXCLUDED.title, subtitle=EXCLUDED.subtitle, emoji=EXCLUDED.emoji, image_url=NULL,
