-- Orange & Date Energy Balls
INSERT INTO public.recipes
  (id, title, subtitle, emoji, image_url, tags, meal, categories, diet, is_kids, prep_minutes, cook_minutes, servings, nutrition, ingredients, dressing, base_ingredients, steps, i18n)
VALUES (
  'orange-energy-balls', 'Orange & Date Energy Balls', 'No-bake, naturally sweet date bites with orange — for lunchboxes and snack attacks', '🟠', NULL,
  ARRAY['Vegan','Kid-Friendly'], ARRAY['Snack','Dessert'], ARRAY['Süßspeise'], ARRAY['vegan','vegetarian','dairy-free'],
  true, 15, 0, 12,
  '{"kcal":146,"protein":3,"carbs":22,"fat":6,"fiber":4}'::jsonb,
  '[{"name":"Medjool dates, pitted","emoji":"🌴","amount":"250 g (about 12)"},{"name":"Orange zest","emoji":"🍊","amount":"of 1 orange"},{"name":"Fresh orange juice","emoji":"🍊","amount":"2 tbsp"},{"name":"Rolled oats","emoji":"🌾","amount":"60 g"},{"name":"Ground almonds","emoji":"🌰","amount":"60 g"},{"name":"Desiccated coconut (plus extra to coat)","emoji":"🥥","amount":"30 g (+20 g)"},{"name":"Chia seeds","emoji":"🖤","amount":"2 tbsp"},{"name":"Raw cacao powder","emoji":"🍫","amount":"1 tbsp"},{"name":"Ground cinnamon","emoji":"🌿","amount":"½ tsp"},{"name":"Fine sea salt","emoji":"🧂","amount":"1 pinch"}]'::jsonb,
  NULL,
  '[]'::jsonb,
  '[{"title":"Blend the dates & orange","text":"Blitz the pitted dates with the orange zest and juice to a thick sticky paste (soak firm dates in warm water 10 min first, then drain).","ings":[]},{"title":"Add the dry & blitz","text":"Add the oats, ground almonds, coconut, chia, cacao, cinnamon and a pinch of salt. Blitz to a soft, deep caramel-brown dough — a splash more juice if dry, more oats if wet.","ings":[]},{"title":"Roll & coat","text":"Roll into 12 walnut-sized balls; roll about half in extra coconut, leave the rest bare and rustic.","ings":[]},{"title":"Chill","text":"Chill at least 30 minutes to firm up. Keeps a week in the fridge or 3 months frozen.","ings":[]}]'::jsonb,
  '{"de":{"title":"Orangen-Dattel-Energiebällchen","subtitle":"Ohne Backen, von Datteln natürlich gesüßt und mit Orange – für die Brotdose und den kleinen Hunger zwischendurch","ingredients":["Medjool-Datteln, entsteint","Abgeriebene Orangenschale","Frisch gepresster Orangensaft","Haferflocken","Gemahlene Mandeln","Kokosraspel (plus etwas zum Wälzen)","Chiasamen","Rohes Kakaopulver","Gemahlener Zimt","Feines Meersalz"],"base":[],"steps":[{"title":"Datteln & Orange pürieren","text":"Püriere die entsteinten Datteln mit der Orangenschale und dem Saft zu einer dicken, klebrigen Paste (feste Datteln vorher 10 Minuten in warmem Wasser einweichen, dann abgießen)."},{"title":"Trockenes dazu & mixen","text":"Gib Haferflocken, gemahlene Mandeln, Kokosraspel, Chiasamen, Kakao, Zimt und eine Prise Salz dazu. Mix alles zu einem weichen, tief karamellbraunen Teig – noch einen Schuss Saft, falls er zu trocken ist, mehr Haferflocken, falls er zu feucht ist."},{"title":"Rollen & wälzen","text":"Forme 12 walnussgroße Kugeln; wälze etwa die Hälfte in zusätzlichen Kokosraspeln und lass die übrigen natürlich und rustikal."},{"title":"Kalt stellen","text":"Stell die Bällchen mindestens 30 Minuten kalt, damit sie fest werden. Sie halten sich eine Woche im Kühlschrank oder 3 Monate im Gefrierfach."}]},"fr":{"title":"Billes énergétiques orange-datte","subtitle":"Sans cuisson, naturellement sucrées aux dattes et parfumées à l''orange — pour la boîte à goûter et les petits creux","ingredients":["Dattes Medjool, dénoyautées","Zeste d''orange","Jus d''orange frais","Flocons d''avoine","Amandes en poudre","Noix de coco râpée (plus un peu pour l''enrobage)","Graines de chia","Cacao cru en poudre","Cannelle en poudre","Sel fin de mer"],"base":[],"steps":[{"title":"Mixer les dattes & l''orange","text":"Mixe les dattes dénoyautées avec le zeste et le jus d''orange jusqu''à obtenir une pâte épaisse et collante (fais d''abord tremper les dattes fermes 10 min dans de l''eau tiède, puis égoutte-les)."},{"title":"Ajouter le sec & mixer","text":"Ajoute les flocons d''avoine, les amandes en poudre, la noix de coco, le chia, le cacao, la cannelle et une pincée de sel. Mixe jusqu''à obtenir une pâte souple d''un beau brun caramel — un filet de jus en plus si c''est trop sec, un peu plus de flocons si c''est trop humide."},{"title":"Rouler & enrober","text":"Forme 12 boules de la taille d''une noix ; roule-en environ la moitié dans de la noix de coco supplémentaire et laisse les autres nature, façon rustique."},{"title":"Réfrigérer","text":"Place au frais au moins 30 minutes pour raffermir. Se conserve une semaine au réfrigérateur ou 3 mois au congélateur."}]},"es":{"title":"Bolitas energéticas de naranja y dátil","subtitle":"Sin horno, dulces por naturaleza gracias a los dátiles y con un toque de naranja — para la fiambrera y los ataques de hambre","ingredients":["Dátiles Medjool, deshuesados","Ralladura de naranja","Zumo de naranja recién exprimido","Copos de avena","Almendra molida","Coco rallado (más un poco para rebozar)","Semillas de chía","Cacao puro en polvo","Canela molida","Sal marina fina"],"base":[],"steps":[{"title":"Triturar los dátiles y la naranja","text":"Tritura los dátiles deshuesados con la ralladura y el zumo de naranja hasta lograr una pasta espesa y pegajosa (si los dátiles están firmes, remójalos antes 10 min en agua templada y escúrrelos)."},{"title":"Añadir lo seco y triturar","text":"Añade los copos de avena, la almendra molida, el coco, la chía, el cacao, la canela y una pizca de sal. Tritura hasta obtener una masa blanda de color caramelo intenso — un chorrito más de zumo si está seca, más avena si está húmeda."},{"title":"Formar y rebozar","text":"Forma 12 bolitas del tamaño de una nuez; reboza aproximadamente la mitad en coco extra y deja el resto al natural, con aspecto rústico."},{"title":"Refrigerar","text":"Refrigera al menos 30 minutos para que cojan cuerpo. Se conservan una semana en la nevera o 3 meses en el congelador."}]}}'::jsonb
)
